import React, {type PropsWithChildren} from "react";
import {ResponsiveElement, useSeparator} from "../../factory";
import type {IFlexComponent} from "@lmb-it/kitsconcerto-types";

const Box =
  ({ children, ref, ...props }:PropsWithChildren<IFlexComponent>) => {
    const { cssProps, nativeProps } = useSeparator<any>(props);
    const { scrollable, entering, exiting, ...restNativeProps } = nativeProps;

    return (
      <ResponsiveElement
        ref={ref}
        as={'Box'}
        scrollable={scrollable}
        entering={entering}
        exiting={exiting}
        additionalStyles={{
          display: "flex",
          flexDirection: "column",
        }}
        cssProps={cssProps}
        nativeProps={restNativeProps}
        children={children}
      />
    );
  }

export default Box;
